def prime_factors(n):
    n = abs(int(n))
    factors = []
    d = 2
    while d * d <= n:
        while n % d == 0:
            factors.append(d)
            n //= d
        d += 1
    if n > 1: factors.append(n)
    return factors
result = sum(set(prime_factors(40)))
print(result)

def next_prime(n):
    n = abs(int(n))
    if n < 2: return 2
    candidate = n + 1
    while True:
        if all(candidate % i != 0 for i in range(2, int(candidate**0.5)+1)):
            return candidate
        candidate += 1
result = next_prime(105)
print(result)
